create table platform_profiles (id uuid primary key,tenant_id uuid not null,merchant_id uuid not null,brand_id uuid not null,storefront_id uuid,platform varchar(30) not null,profile_scope varchar(20) not null,account_name varchar(255),profile_url text,external_id varchar(255),verification_status varchar(30) not null default 'UNVERIFIED',last_observed_at timestamptz,last_verified_at timestamptz,notes text,deleted boolean not null default false,created_at timestamptz not null,updated_at timestamptz not null,created_by uuid,updated_by uuid,version bigint not null default 0);
create table platform_profile_fields (id uuid primary key,tenant_id uuid not null,merchant_id uuid not null,profile_id uuid not null,field_key varchar(50) not null,item_key varchar(100),field_group_key varchar(100),version_no int not null,is_current boolean not null default true,value_json jsonb not null,normalized_text text,source_type varchar(30) not null,source_asset_id uuid,external_url text,observed_at timestamptz,verified_at timestamptz,status varchar(30) not null default 'UNVERIFIED',created_at timestamptz not null,created_by uuid,version bigint not null default 0);
create table platform_asset_gaps (id uuid primary key,tenant_id uuid not null,merchant_id uuid not null,platform_profile_id uuid not null,platform_field_id uuid,fact_id uuid,fact_version_id uuid,gap_type varchar(30) not null,field_key varchar(50) not null,item_key varchar(100),platform_value_snapshot jsonb,fact_value_snapshot jsonb,difference_summary text,priority varchar(20) not null,status varchar(20) not null default 'OPEN',first_detected_at timestamptz not null,last_detected_at timestamptz not null,resolved_at timestamptz,resolution_notes text,generated_task_id uuid,created_at timestamptz not null,updated_at timestamptz not null,created_by uuid,updated_by uuid,version bigint not null default 0);
create index idx_platform_profiles_scope on platform_profiles(tenant_id,merchant_id,platform,deleted);create index idx_platform_fields_current on platform_profile_fields(tenant_id,profile_id,field_key,is_current);create index idx_platform_gaps_open on platform_asset_gaps(tenant_id,merchant_id,status);
